import{_ as d,c as e,o as r,a0 as a}from"./chunks/framework.C-aSrekC.js";const _=JSON.parse('{"title":"TileMap 属性","description":"","frontmatter":{},"headers":[],"relativePath":"2.base/03.mapProps.md","filePath":"2.base/03.mapProps.md","lastUpdated":1741063516000}'),o={name:"2.base/03.mapProps.md"};function i(n,t,s,l,p,m){return r(),e("div",null,t[0]||(t[0]=[a('<h1 id="tilemap-属性" tabindex="-1">TileMap 属性 <a class="header-anchor" href="#tilemap-属性" aria-label="Permalink to &quot;TileMap 属性&quot;">​</a></h1><p>TileMap 继承于 threejs 的 Mesh 类，除了 Mesh 的属性外，它还有如下属性：</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>imgSource</td><td>iSource 或 iSource[]</td><td>设置或取得地图的影像数据源，修改后必须调用reLoad方法才能生效</td></tr><tr><td>demSource</td><td>ISource</td><td>设置或取得地图的地形数据，修改后必须调用reLoad方法才能生效源</td></tr><tr><td>autoUpdate</td><td>boolean</td><td>默认为 true，指定是否在每帧渲染中更新地图模型和数据。</td></tr><tr><td>autoPosition</td><td>boolean</td><td>默认为 false，指定是否在每帧渲染中根据视野内瓦片的平均海拔高度调整地图模型的位置（高度）。地图模型默认位置在海拔 0 米，但在高海拔地区，地面在视野里显得很高，打开自动调整会将模型位置调整为地面平均海拔高度而不是 0 米。如果你不明白它是啥意思，保持默认值</td></tr><tr><td>useWorker</td><td>boolean</td><td>默认为 true，是否使用 WebWorker 解析数据，避免数据解析期间的渲染的卡顿</td></tr><tr><td>maxZInView</td><td>number</td><td>取得视野内地形的最高海拔高度</td></tr><tr><td>minZInView</td><td>number</td><td>取得视野内地形的最低海拔高度</td></tr><tr><td>avgZInView</td><td>number</td><td>取得视野内地形的平均海拔高度</td></tr><tr><td>loadCacheSize</td><td>number</td><td>默认为 200，设置或取得瓦片数据的缓存大小，单位为块。较大的缓存能提高运行速度，但会耗费较多内存</td></tr><tr><td>LODThreshold</td><td>number</td><td>默认为 1，设置瓦片 LOD 阈值系数。TileMap 本质上是一个动态 LOD 模型，它根据瓦片离摄像机的距离对模型进行细化或合并，该值越大瓦片细化越快，越小瓦片合并越快快</td></tr><tr><td>attributions</td><td>string[]</td><td>取得瓦片数据归属者信息，如版权等，来自瓦片数据源定义中的 attributions 属性</td></tr><tr><td>tileCount</td><td>Object</td><td>取得瓦片统计信息，如瓦片总数、叶子瓦片数、可视瓦片数等，主要用来进行调试</td></tr></tbody></table>',3)]))}const b=d(o,[["render",i]]);export{_ as __pageData,b as default};
